#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

#define MAX_SESSIONS 100
#define SESSION_TIMEOUT 300 // 5 minutes

typedef struct {
    char session_id[36];
    char *data;
    time_t creation_time;
} Session;

Session session_cache[MAX_SESSIONS];

void init_cache() {
    for (int i = 0; i < MAX_SESSIONS; i++) {
        session_cache[i].session_id[0] = '\0';
        session_cache[i].data = NULL;
        session_cache[i].creation_time = 0;
    }
}

int create_session(const char *session_id, const char *data) {
    for (int i = 0; i < MAX_SESSIONS; i++) {
        if (strcmp(session_cache[i].session_id, session_id) == 0 || session_cache[i].session_id[0] == '\0') {
            strcpy(session_cache[i].session_id, session_id);
            session_cache[i].data = malloc(strlen(data) + 1);
            strcpy(session_cache[i].data, data);
            session_cache[i].creation_time = time(NULL);
            return 1;
        }
    }
    return 0; // Cache is full
}

char* access_session(const char *session_id) {
    for (int i = 0; i < MAX_SESSIONS; i++) {
        if (strcmp(session_cache[i].session_id, session_id) == 0) {
            if (difftime(time(NULL), session_cache[i].creation_time) < SESSION_TIMEOUT) {
                return session_cache[i].data;
            } else {
                free(session_cache[i].data);
                session_cache[i].data = NULL; // Invalidate data but keep ID
                return NULL;
            }
        }
    }
    return NULL; // Session not found
}

void invalidate_session(const char *session_id) {
    for (int i = 0; i < MAX_SESSIONS; i++) {
        if (strcmp(session_cache[i].session_id, session_id) == 0) {
            free(session_cache[i].data);
            session_cache[i].data = NULL;
            session_cache[i].creation_time = 0; // Invalidate session
            return;
        }
    }
}

void clear_expired_sessions() {
    for (int i = 0; i < MAX_SESSIONS; i++) {
        if (session_cache[i].session_id[0] != '\0' && 
            difftime(time(NULL), session_cache[i].creation_time) >= SESSION_TIMEOUT) {
            free(session_cache[i].data);
            session_cache[i].data = NULL; // Invalidate data but keep ID
        }
    }
}

